import React, { useState, useEffect } from "react";
import axios from "axios";

const Sidebar = () => {
  return (
    <aside className="w-64 bg-gray-800 text-white min-h-screen p-6 fixed">
      <h2 className="text-2xl font-bold mb-6">My Sidebar</h2>
      <nav className="space-y-4">
        <a href="/" className="block hover:text-gray-300">Home</a>
        <a href="/blogs" className="block hover:text-gray-300">Blogs</a>
        <a href="/categories" className="block hover:text-gray-300">Categories</a>
        {/* Add more sidebar links here */}
      </nav>
    </aside>
  );
};

const BlogManage = () => {
  const [blogs, setBlogs] = useState([]);
  const [form, setForm] = useState({
    title: "",
    full_content: "",
    image: null, // changed from image_url to file
    category_id: "",
  });
  const [editId, setEditId] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  // Fetch blogs
  const fetchBlogs = async () => {
    setLoading(true);
    setError("");
    try {
      const token = localStorage.getItem("token");
      const config = token
        ? { headers: { Authorization: `Bearer ${token}` } }
        : {};
      const res = await axios.get("http://localhost:5000/api/blogs", config);
      setBlogs(res.data);
    } catch (err) {
      setError("Failed to fetch blogs.");
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchBlogs();
  }, []);

  const handleChange = (e) => {
    const { name, value, files } = e.target;
    if (name === "image") {
      setForm((prev) => ({ ...prev, image: files[0] }));
    } else {
      setForm((prev) => ({ ...prev, [name]: value }));
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");
    setLoading(true);

    try {
      const token = localStorage.getItem("token");
      const config = {
        headers: {
          Authorization: token ? `Bearer ${token}` : "",
          "Content-Type": "multipart/form-data",
        },
      };

      // Use FormData to send file
      const formData = new FormData();
      formData.append("title", form.title);
      formData.append("full_content", form.full_content);
      formData.append("category_id", Number(form.category_id));
      if (form.image) {
        formData.append("image", form.image);
      }

      if (editId) {
        await axios.put(`http://localhost:5000/api/blogs/${editId}`, formData, config);
        setEditId(null);
      } else {
        await axios.post("http://localhost:5000/api/blogs", formData, config);
      }

      setForm({
        title: "",
        full_content: "",
        image: null,
        category_id: "",
      });

      await fetchBlogs();
    } catch (err) {
      setError(
        err.response?.data?.message || "Failed to save blog. Check console for details."
      );
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleEdit = (blog) => {
    setForm({
      title: blog.title,
      full_content: blog.full_content || "",
      image: null, // no file on edit, user must re-upload if needed
      category_id: blog.category_id.toString(),
    });
    setEditId(blog.id);
  };

  const handleDelete = async (id) => {
    if (!window.confirm("Delete this blog?")) return;
    setLoading(true);
    setError("");

    try {
      const token = localStorage.getItem("token");
      const config = token
        ? { headers: { Authorization: `Bearer ${token}` } }
        : {};
      await axios.delete(`http://localhost:5000/api/blogs/${id}`, config);
      await fetchBlogs();
    } catch (err) {
      setError(
        err.response?.data?.message || "Failed to delete blog. Check console."
      );
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex min-h-screen bg-gray-100">
      {/* Sidebar */}
      <Sidebar />

      {/* Main content area */}
      <main className="flex-1 ml-64 p-6">
        <h2 className="text-3xl font-semibold mb-6 text-gray-800">
          {editId ? "Edit Blog" : "Add Blog"}
        </h2>

        {error && (
          <p className="mb-4 text-red-600 font-medium bg-red-100 p-3 rounded">
            {error}
          </p>
        )}

        <form onSubmit={handleSubmit} className="space-y-5 max-w-3xl">
          {/* Title */}
          <div>
            <label className="block mb-1 font-semibold text-gray-700">Title</label>
            <input
              name="title"
              value={form.title}
              onChange={handleChange}
              placeholder="Title"
              className="w-full p-3 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-400"
              required
            />
          </div>

          {/* Full Content */}
          <div>
            <label className="block mb-1 font-semibold text-gray-700">
              Full Content
            </label>
            <textarea
              name="full_content"
              value={form.full_content}
              onChange={handleChange}
              placeholder="Full detailed content"
              rows={6}
              className="w-full p-3 border border-gray-300 rounded-md resize-none focus:outline-none focus:ring-2 focus:ring-blue-400"
              required
            />
          </div>

          {/* Image Upload */}
          <div>
            <label className="block mb-1 font-semibold text-gray-700">Upload Image</label>
            <input
              type="file"
              name="image"
              accept="image/*"
              onChange={handleChange}
              className="w-full p-1 border border-gray-300 rounded-md"
            />
          </div>

          {/* Category */}
          <div>
            <label className="block mb-1 font-semibold text-gray-700">Category</label>
            <input
              type="number"
              name="category_id"
              value={form.category_id}
              onChange={handleChange}
              placeholder="Category ID"
              className="w-full p-3 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-400"
              required
              min={1}
            />
          </div>

          <button
            type="submit"
            disabled={loading}
            className={`w-full py-3 rounded-md text-white font-semibold transition-colors ${
              loading ? "bg-gray-400 cursor-not-allowed" : "bg-blue-600 hover:bg-blue-700"
            }`}
          >
            {editId ? "Update Blog" : "Add Blog"}
          </button>
        </form>

        {/* Blogs Table */}
        <div className="mt-10 overflow-x-auto max-w-5xl">
          {loading && <p className="text-center text-gray-600 mb-3">Loading...</p>}

          <table className="min-w-full border border-gray-300 rounded-md bg-white">
            <thead className="bg-gray-100">
              <tr>
                <th className="py-3 px-4 border-b text-left">ID</th>
                <th className="py-3 px-4 border-b text-left">Title</th>
                <th className="py-3 px-4 border-b text-left">Category ID</th>
                <th className="py-3 px-4 border-b text-center">Actions</th>
              </tr>
            </thead>
            <tbody>
              {blogs.length === 0 && !loading && (
                <tr>
                  <td colSpan="4" className="py-6 text-center text-gray-500">
                    No blogs found.
                  </td>
                </tr>
              )}
              {blogs.map((blog) => (
                <tr key={blog.id} className="hover:bg-gray-50">
                  <td className="py-2 px-4 border-b">{blog.id}</td>
                  <td className="py-2 px-4 border-b">{blog.title}</td>
                  <td className="py-2 px-4 border-b text-center">{blog.category_id}</td>
                  <td className="py-2 px-4 border-b text-center space-x-2">
                    <button
                      onClick={() => handleEdit(blog)}
                      className="bg-blue-600 hover:bg-blue-700 text-white px-3 py-1 rounded"
                    >
                      Edit
                    </button>
                    <button
                      onClick={() => handleDelete(blog.id)}
                      className="bg-red-600 hover:bg-red-700 text-white px-3 py-1 rounded"
                    >
                      Delete
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </main>
    </div>
  );
};

export default BlogManage;
